import React, { useState, useEffect } from "react";
import { useParams, useNavigate, Link } from "react-router-dom";
import axios from "axios";
import { base_url } from "../utils/axiosConfig";
import Footer from "./Footer";

const HealthAdviceDetails = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [advice, setAdvice] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    if (!id) return;
    window.scrollTo(0, 0);
    setLoading(true);
    setError(null);
    axios
      .get(`${base_url}health-advice/${id}`)
      .then((res) => setAdvice(res.data))
      .catch((err) => setError(err.message))
      .finally(() => setLoading(false));
  }, [id]);

  const fallback =
    "https://images.unsplash.com/photo-1607619056574-7b8d3ee536b2?auto=format&fit=crop&w=1200&q=80";

  if (loading) {
    return (
      <div style={s.loadingWrap}>
        <div style={s.loadingSpinner} />
        <p style={s.loadingText}>Loading protocol...</p>
      </div>
    );
  }

  if (error || !advice) {
    return (
      <div style={s.loadingWrap}>
        <div style={{ fontSize: 48, marginBottom: 16 }}>🩺</div>
        <p style={{ fontWeight: 700, color: "#1e293b", marginBottom: 8 }}>Guide not found</p>
        <p style={{ color: "#94a3b8", fontSize: 14, marginBottom: 24 }}>{error || "This protocol may have been removed."}</p>
        <button onClick={() => navigate("/care-suggestions")} style={s.backPillBtn}>
          ← Return to Library
        </button>
      </div>
    );
  }

  const heroImg = advice.image?.secure_url || advice.image?.url || fallback;

  return (
    <>
      <style>{CSS}</style>
      <div className="had-root">
        {/* ─ Sticky Nav ─ */}
        <nav className="had-nav">
          <button className="had-back" onClick={() => navigate(-1)}>
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="m15 18-6-6 6-6"/></svg>
            Back
          </button>
          <span className="had-brand">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#14b8a6" strokeWidth="2.5"><path d="M22 12h-4l-3 9L9 3l-3 9H2"/></svg>
            Pulse Health Guide
          </span>
          <div style={{ width: 70 }} />
        </nav>

        {/* ─ Hero Image ─ */}
        <div className="had-hero-img-container">
          <img
            src={heroImg}
            alt={advice.conditionName}
            className="had-hero-img"
            onError={(e) => { e.target.src = fallback; }}
          />
          <div className="had-hero-gradient" />
          <div className="had-hero-tag">Clinical Protocol</div>
        </div>

        {/* ─ Main Content ─ */}
        <main className="had-main">

          {/* Title Block */}
          <div className="had-title-block">
            <div className="had-pill-badge">
              <span className="had-pill-dot" />
              Pharmacist Verified
            </div>
            <h1 className="had-title">{advice.conditionName}</h1>
            <div className="had-meta-row">
              <span className="had-meta-item">
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="12" cy="12" r="10"/><path d="M12 6v6l4 2"/></svg>
                Updated {new Date(advice.updatedAt).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })}
              </span>
              <span className="had-meta-separator">·</span>
              <span className="had-meta-item">5 min read</span>
            </div>
          </div>

          <div className="had-content-grid">
            {/* Left Column */}
            <div className="had-left-col">

              {/* Symptoms */}
              {advice.keySymptoms?.length > 0 && (
                <section className="had-section">
                  <div className="had-section-label">Symptom Index</div>
                  <h2 className="had-section-heading">Identifying Signs</h2>
                  <div className="had-symptoms-grid">
                    {advice.keySymptoms.map((s, i) => (
                      <div key={i} className="had-symptom-chip">
                        <span className="had-symptom-dot" />
                        {s}
                      </div>
                    ))}
                  </div>
                </section>
              )}

              {/* Advice Text */}
              <section className="had-section">
                <div className="had-section-label">Expert Guidance</div>
                <h2 className="had-section-heading">Recovery Protocol</h2>
                <div className="had-advice-text">{advice.healthAdvice}</div>
              </section>

              {/* Products on mobile — inline */}
              {advice.products?.length > 0 && (
                <section className="had-section had-mobile-products">
                  <div className="had-section-label">Pharmacist Picks</div>
                  <h2 className="had-section-heading">OTC Recommendations</h2>
                  <div className="had-product-list">
                    {advice.products.map((p) => (
                      <Link
                        key={p._id}
                        to={`/productdetails/${p._id}`}
                        className="had-product-row"
                      >
                        <div className="had-product-img-wrap">
                          <img
                            src={(Array.isArray(p.colors?.[0]?.images) ? (Array.isArray(p.colors?.[0]?.images) ? (Array.isArray(p.colors?.[0]?.images) ? p.colors?.[0]?.images?.[0]?.secure_url : p.colors?.[0]?.images?.secure_url) : p.colors?.[0]?.images?.secure_url) : p.colors?.[0]?.images?.secure_url) || ""}
                            alt={p.title}
                            className="had-product-img"
                            onError={(e) => { e.target.style.opacity = 0.2; }}
                          />
                        </div>
                        <div className="had-product-info">
                          <span className="had-product-name">{p.title}</span>
                          <span className="had-product-price">ETB {Number(p.price).toLocaleString()}</span>
                        </div>
                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#14b8a6" strokeWidth="2.5"><path d="m9 18 6-6-6-6"/></svg>
                      </Link>
                    ))}
                  </div>
                </section>
              )}

              {/* Disclaimer */}
              <div className="had-disclaimer">
                <span className="had-disclaimer-icon">⚠️</span>
                <p>
                  <strong>Medical Disclaimer:</strong> This guide is for informational purposes only and has been reviewed by licensed pharmacists. It does not constitute medical diagnosis or treatment. Consult a qualified health professional if symptoms are severe or persistent.
                </p>
              </div>
            </div>

            {/* Right Sidebar — Desktop only */}
            <aside className="had-sidebar">
              <div className="had-sidebar-card">
                <div className="had-sidebar-header">
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#14b8a6" strokeWidth="2.5"><path d="M12 2H2v10l9.29 9.29c.94.94 2.48.94 3.42 0l6.58-6.58c.94-.94.94-2.48 0-3.42L12 2Z"/><path d="M7 7h.01"/></svg>
                  <span>Recommended Treatments</span>
                </div>

                {advice.products?.length > 0 ? (
                  <div className="had-sidebar-list">
                    {advice.products.map((p) => (
                      <Link
                        key={p._id}
                        to={`/productdetails/${p._id}`}
                        className="had-sidebar-product"
                      >
                        <div className="had-sidebar-img-wrap">
                          <img
                            src={(Array.isArray(p.colors?.[0]?.images) ? (Array.isArray(p.colors?.[0]?.images) ? (Array.isArray(p.colors?.[0]?.images) ? p.colors?.[0]?.images?.[0]?.secure_url : p.colors?.[0]?.images?.secure_url) : p.colors?.[0]?.images?.secure_url) : p.colors?.[0]?.images?.secure_url) || ""}
                            alt={p.title}
                            onError={(e) => { e.target.style.opacity = 0.1; }}
                          />
                        </div>
                        <div className="had-sidebar-product-info">
                          <span className="had-sidebar-product-name">{p.title}</span>
                          <span className="had-sidebar-product-price">ETB {Number(p.price).toLocaleString()}</span>
                        </div>
                        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#14b8a6" strokeWidth="2.5"><path d="m9 18 6-6-6-6"/></svg>
                      </Link>
                    ))}
                  </div>
                ) : (
                  <p style={{ fontSize: 13, color: "rgba(255,255,255,0.3)", fontWeight: 600, padding: "16px 0" }}>No products linked yet.</p>
                )}

                <div className="had-sidebar-trust">
                  <div className="had-trust-row">
                    <span>✓</span> ISO-certified products
                  </div>
                  <div className="had-trust-row">
                    <span>✓</span> Free delivery on orders above ETB 500
                  </div>
                </div>
              </div>

              {/* Symptoms sidebar widget */}
              {advice.keySymptoms?.length > 0 && (
                <div className="had-symptoms-widget">
                  <div className="had-symptoms-widget-title">Key Symptoms</div>
                  <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginTop: 12 }}>
                    {advice.keySymptoms.map((s, i) => (
                      <span key={i} className="had-symptom-widget-pill">{s}</span>
                    ))}
                  </div>
                </div>
              )}
            </aside>
          </div>
        </main>

        <Footer />
      </div>
    </>
  );
};

const CSS = `
  @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&family=Plus+Jakarta+Sans:wght@700;800;900&display=swap');

  * { box-sizing: border-box; margin: 0; padding: 0; }

  .had-root {
    font-family: 'Inter', -apple-system, sans-serif;
    background: #ffffff;
    min-height: 100vh;
    color: #0f172a;
  }

  /* ── NAV ── */
  .had-nav {
    position: sticky;
    top: 0;
    z-index: 200;
    background: rgba(255,255,255,0.92);
    backdrop-filter: blur(16px);
    -webkit-backdrop-filter: blur(16px);
    border-bottom: 1px solid #f1f5f9;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 20px;
    height: 52px;
  }

  .had-back {
    display: flex;
    align-items: center;
    gap: 6px;
    background: #f8fafc;
    border: 1px solid #e2e8f0;
    border-radius: 10px;
    padding: 7px 14px;
    font-size: 13px;
    font-weight: 600;
    color: #475569;
    cursor: pointer;
    transition: all 0.2s;
  }
  .had-back:hover { background: #f0fdfa; border-color: #14b8a6; color: #14b8a6; }

  .had-brand {
    display: flex;
    align-items: center;
    gap: 6px;
    font-size: 12px;
    font-weight: 800;
    color: #0f172a;
    text-transform: uppercase;
    letter-spacing: 0.08em;
  }

  /* ── HERO IMAGE ── */
  .had-hero-img-container {
    width: 100%;
    height: 380px;
    position: relative;
    overflow: hidden;
    background: #f1f5f9;
  }

  .had-hero-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    display: block;
  }

  .had-hero-gradient {
    position: absolute;
    inset: 0;
    background: linear-gradient(to bottom, transparent 40%, rgba(0,0,0,0.35) 100%);
  }

  .had-hero-tag {
    position: absolute;
    top: 16px;
    left: 20px;
    background: rgba(255,255,255,0.15);
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);
    border: 1px solid rgba(255,255,255,0.3);
    color: #ffffff;
    font-size: 10px;
    font-weight: 800;
    text-transform: uppercase;
    letter-spacing: 0.12em;
    padding: 6px 12px;
    border-radius: 8px;
  }

  @media (max-width: 640px) {
    .had-hero-img-container { height: 260px; }
  }

  /* ── MAIN CONTENT AREA ── */
  .had-main {
    max-width: 1100px;
    margin: 0 auto;
    padding: 0 20px 60px;
  }

  /* ── TITLE BLOCK ── */
  .had-title-block {
    padding: 40px 0 36px;
    border-bottom: 1px solid #f1f5f9;
    margin-bottom: 40px;
  }

  .had-pill-badge {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    background: #f0fdfa;
    border: 1px solid #ccfbf1;
    color: #0d9488;
    font-size: 11px;
    font-weight: 700;
    padding: 5px 12px;
    border-radius: 100px;
    margin-bottom: 16px;
    text-transform: uppercase;
    letter-spacing: 0.06em;
  }

  .had-pill-dot {
    width: 6px;
    height: 6px;
    border-radius: 50%;
    background: #14b8a6;
    animation: pulse-dot 2s infinite;
  }

  @keyframes pulse-dot {
    0%, 100% { opacity: 1; transform: scale(1); }
    50% { opacity: 0.5; transform: scale(0.8); }
  }

  .had-title {
    font-family: 'Plus Jakarta Sans', sans-serif;
    font-size: clamp(32px, 5vw, 52px);
    font-weight: 900;
    letter-spacing: -0.04em;
    line-height: 1.05;
    color: #0f172a;
    margin-bottom: 20px;
  }

  .had-meta-row {
    display: flex;
    align-items: center;
    gap: 10px;
    flex-wrap: wrap;
  }

  .had-meta-item {
    display: flex;
    align-items: center;
    gap: 5px;
    font-size: 13px;
    color: #94a3b8;
    font-weight: 500;
  }

  .had-meta-separator { color: #e2e8f0; font-size: 16px; }

  /* ── CONTENT GRID ── */
  .had-content-grid {
    display: grid;
    grid-template-columns: 1fr 300px;
    gap: 48px;
    align-items: start;
  }

  @media (max-width: 1000px) {
    .had-content-grid {
      grid-template-columns: 1fr;
      gap: 0;
    }
    .had-sidebar { display: none; }
    .had-mobile-products { display: block !important; }
  }

  @media (min-width: 1001px) {
    .had-mobile-products { display: none !important; }
  }

  /* ── SECTION STYLES ── */
  .had-section {
    margin-bottom: 52px;
  }

  .had-section-label {
    font-size: 10px;
    font-weight: 800;
    color: #14b8a6;
    text-transform: uppercase;
    letter-spacing: 0.18em;
    margin-bottom: 10px;
  }

  .had-section-heading {
    font-family: 'Plus Jakarta Sans', sans-serif;
    font-size: 26px;
    font-weight: 900;
    letter-spacing: -0.03em;
    color: #0f172a;
    margin-bottom: 24px;
  }

  /* ── SYMPTOMS ── */
  .had-symptoms-grid {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
  }

  .had-symptom-chip {
    display: flex;
    align-items: center;
    gap: 8px;
    background: #f8fafc;
    border: 1px solid #e2e8f0;
    border-radius: 12px;
    padding: 10px 16px;
    font-size: 13px;
    font-weight: 600;
    color: #334155;
    text-transform: capitalize;
    transition: all 0.2s;
  }
  .had-symptom-chip:hover { border-color: #14b8a6; background: #f0fdfa; color: #0d9488; }

  .had-symptom-dot {
    width: 6px;
    height: 6px;
    border-radius: 50%;
    background: #14b8a6;
    flex-shrink: 0;
  }

  /* ── ADVICE TEXT ── */
  .had-advice-text {
    font-size: 17px;
    line-height: 1.85;
    color: #374151;
    font-weight: 400;
    white-space: pre-wrap;
    letter-spacing: -0.01em;
  }

  /* ── DISCLAIMER ── */
  .had-disclaimer {
    display: flex;
    gap: 14px;
    background: linear-gradient(135deg, #fffbeb, #fef3c7);
    border: 1px solid #fde68a;
    border-radius: 20px;
    padding: 20px 24px;
    margin-bottom: 40px;
  }
  .had-disclaimer-icon { font-size: 20px; flex-shrink: 0; line-height: 1.7; }
  .had-disclaimer p { font-size: 13px; color: #78350f; line-height: 1.7; font-weight: 500; }
  .had-disclaimer strong { font-weight: 800; color: #92400e; }

  /* ── MOBILE PRODUCTS ── */
  .had-product-list { display: flex; flex-direction: column; gap: 12px; }

  .had-product-row {
    display: flex;
    align-items: center;
    gap: 14px;
    background: #f8fafc;
    border: 1px solid #f1f5f9;
    border-radius: 18px;
    padding: 14px;
    text-decoration: none;
    transition: all 0.2s;
  }
  .had-product-row:hover { border-color: #14b8a6; background: #f0fdfa; }

  .had-product-img-wrap {
    width: 60px; height: 60px;
    border-radius: 14px;
    background: #fff;
    border: 1px solid #e2e8f0;
    flex-shrink: 0;
    overflow: hidden;
    display: flex; align-items: center; justify-content: center;
  }
  .had-product-img { width: 100%; height: 100%; object-fit: contain; }

  .had-product-info { flex: 1; overflow: hidden; }
  .had-product-name { 
    display: block; font-size: 14px; font-weight: 700; color: #1e293b;
    white-space: nowrap; overflow: hidden; text-overflow: ellipsis; margin-bottom: 4px;
  }
  .had-product-price { font-size: 13px; font-weight: 800; color: #14b8a6; }

  /* ── SIDEBAR ── */
  .had-sidebar { position: sticky; top: 70px; }

  .had-sidebar-card {
    background: #0f172a;
    border-radius: 24px;
    padding: 28px;
    margin-bottom: 20px;
  }

  .had-sidebar-header {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 11px;
    font-weight: 800;
    text-transform: uppercase;
    letter-spacing: 0.14em;
    color: #14b8a6;
    margin-bottom: 24px;
    padding-bottom: 16px;
    border-bottom: 1px solid rgba(255,255,255,0.06);
  }

  .had-sidebar-list { display: flex; flex-direction: column; gap: 12px; }

  .had-sidebar-product {
    display: flex;
    align-items: center;
    gap: 12px;
    background: rgba(255,255,255,0.04);
    border-radius: 16px;
    padding: 12px;
    text-decoration: none;
    color: #fff;
    transition: all 0.2s;
    border: 1px solid rgba(255,255,255,0.04);
  }
  .had-sidebar-product:hover { background: rgba(20,184,166,0.12); border-color: rgba(20,184,166,0.3); transform: translateX(4px); }

  .had-sidebar-img-wrap {
    width: 52px; height: 52px;
    border-radius: 12px;
    background: #fff;
    overflow: hidden;
    flex-shrink: 0;
    display: flex; align-items: center; justify-content: center;
  }
  .had-sidebar-img-wrap img { width: 100%; height: 100%; object-fit: contain; }

  .had-sidebar-product-info { flex: 1; overflow: hidden; }
  .had-sidebar-product-name { 
    display: block; font-size: 13px; font-weight: 700; color: #fff;
    white-space: nowrap; overflow: hidden; text-overflow: ellipsis; margin-bottom: 3px;
  }
  .had-sidebar-product-price { font-size: 12px; font-weight: 800; color: #14b8a6; }

  .had-sidebar-trust {
    margin-top: 20px;
    padding-top: 20px;
    border-top: 1px solid rgba(255,255,255,0.06);
    display: flex;
    flex-direction: column;
    gap: 8px;
  }
  .had-trust-row { font-size: 11px; font-weight: 600; color: rgba(255,255,255,0.3); display: flex; gap: 6px; }
  .had-trust-row span { color: #4ade80; }

  .had-symptoms-widget {
    background: #f8fafc;
    border: 1px solid #f1f5f9;
    border-radius: 20px;
    padding: 20px;
  }
  .had-symptoms-widget-title {
    font-size: 11px; font-weight: 800; color: #94a3b8; text-transform: uppercase; letter-spacing: 0.12em;
  }
  .had-symptom-widget-pill {
    background: #fff; border: 1px solid #e2e8f0;
    border-radius: 8px; padding: 5px 12px;
    font-size: 12px; font-weight: 600; color: #475569;
    text-transform: capitalize;
    display: inline-block;
  }
`;

// Loading / error helper styles
const s = {
  loadingWrap: { display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", minHeight: "100vh", background: "#fff" },
  loadingSpinner: { width: 40, height: 40, border: "3px solid #f1f5f9", borderTop: "3px solid #14b8a6", borderRadius: "50%", animation: "had-spin 0.8s linear infinite", marginBottom: 16 },
  loadingText: { fontSize: 14, fontWeight: 600, color: "#94a3b8" },
  backPillBtn: { background: "#0f172a", color: "#fff", border: "none", padding: "12px 24px", borderRadius: 12, fontWeight: 700, fontSize: 14, cursor: "pointer" },
};

export default HealthAdviceDetails;
